const STORAGE_KEY = 'notepad-content';
const STORAGE_TIMESTAMP_KEY = 'notepad-saved-at';
const ON_AUTOSAVED = 'OnAutosaved';

let dotNetRef;
let autoSaveInterval;
let lastKnownContent = '';
let hasUnsavedChanges = false;

function onBeforeUnload(e) {
    if (hasUnsavedChanges) {
        e.preventDefault();
    }
}

export function initialize(dotNetReference) {
    dotNetRef = dotNetReference;
    window.addEventListener('beforeunload', onBeforeUnload);
}

export function loadContent() {
    const content = localStorage.getItem(STORAGE_KEY) ?? '';
    const savedAt = localStorage.getItem(STORAGE_TIMESTAMP_KEY) ?? '';
    lastKnownContent = content;
    hasUnsavedChanges = false;
    return { content, savedAt };
}

export function saveContent(content) {
    const now = new Date().toLocaleTimeString([], {
        hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false
    });
    localStorage.setItem(STORAGE_KEY, content);
    localStorage.setItem(STORAGE_TIMESTAMP_KEY, now);
    lastKnownContent = content;
    hasUnsavedChanges = false;
    return now;
}

export function clearContent() {
    localStorage.removeItem(STORAGE_KEY);
    localStorage.removeItem(STORAGE_TIMESTAMP_KEY);
    lastKnownContent = '';
    hasUnsavedChanges = false;
}

export function startAutoSave(intervalMs) {
    stopAutoSave();
    autoSaveInterval = setInterval(async () => {
        try {
            await dotNetRef.invokeMethodAsync(ON_AUTOSAVED);
        } catch { /* circuit disconnected */ }
    }, intervalMs);
}

export function stopAutoSave() {
    if (autoSaveInterval) {
        clearInterval(autoSaveInterval);
        autoSaveInterval = undefined;
    }
}

export function markDirty(content) {
    hasUnsavedChanges = content !== lastKnownContent;
}

export function dispose() {
    stopAutoSave();
    window.removeEventListener('beforeunload', onBeforeUnload);
    dotNetRef = undefined;
}

