toolArgs.file_text:
@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="notepad-container">
    <textarea class="notepad-textarea" @bind="Content" @bind:event="oninput" @bind:after="OnContentChanged"></textarea>

    <div class="notepad-toolbar">
        <button class="btn btn-primary" @onclick="SaveNowAsync">Save now</button>
        <button class="btn btn-danger" @onclick="ClearAsync">Clear</button>
        @if (!string.IsNullOrEmpty(_lastSavedAt))
        {
            <span class="notepad-status">Last saved at @_lastSavedAt</span>
        }
    </div>
</div>

@code {
    private const int AutoSaveIntervalMs = 30_000;

    private NotepadInterop? _interop;
    private DotNetObjectReference<Notepad>? _dotNetRef;
    private string? _lastSavedAt;

    public string Content { get; set; } = string.Empty;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            _dotNetRef = DotNetObjectReference.Create(this);

            await _interop.InitializeAsync(_dotNetRef);

            var saved = await _interop.LoadContentAsync();
            Content = saved.Content;
            _lastSavedAt = saved.SavedAt;

            await _interop.StartAutoSaveAsync(AutoSaveIntervalMs);
            StateHasChanged();
        }
    }

    private async Task OnContentChanged()
    {
        if (_interop is not null)
        {
            await _interop.MarkDirtyAsync(Content);
        }
    }

    [JSInvokable]
    public async Task OnAutosaved()
    {
        await InvokeAsync(async () =>
        {
            if (_interop is not null)
            {
                _lastSavedAt = await _interop.SaveContentAsync(Content);
                StateHasChanged();
            }
        });
    }

    private async Task SaveNowAsync()
    {
        if (_interop is not null)
        {
            _lastSavedAt = await _interop.SaveContentAsync(Content);
        }
    }

    private async Task ClearAsync()
    {
        if (_interop is not null)
        {
            await _interop.ClearContentAsync();
            Content = string.Empty;
            _lastSavedAt = null;
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_interop is not null)
        {
            await _interop.DisposeAsync();
        }

        _dotNetRef?.Dispose();
    }
}

